INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_416185','Й а в Лісі в Лісі й а в Медоборі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда) і Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) Сиве Голуб''є, Святе Різдво: Вогонь як Світотворче начало. Піди принеси Святе Різдво. Мене перейшло Сиве Голуб''є. Тому из очий Искри скакали. Блудили Блудці Сімсот Молодців. А всі Святії ослоном сіли Й а в Лісі в Лісі й а в Медоборі Ой Дзяде Дзяде на Твойму Дворі Ой позволь Пан Хазяїн нам Колядочку сказать Там у Нашого Пана Сподара Вибирай си кого любиш. На Городі під Цибулькою сидить Голуб із Голубкою Сидять Святі з Перами промовляють Cловами. Три Гискри впало Три Морі стало. (1) Бо сьвятий Петро ся зосоломив — перелякався РОЗСПІВ 1: Йа- в лі-сі- в лі-сі- йа- в ме-до-бо-рі- Дай- Бо-же- Повторення кожної стрічки: Йа- в лі-сі- в лі-сі- йа- в ме-до-бо-рі- Дай- Бо- РОЗСПІВ 2: Йа- в лі-сі- в лі-сі- йа- в ме-до-бо-рі- Приспів: Свя-тий- Ве-чір- йа- в ме-до-бо-рі- Доб-рий- Ве-чір- йа- в ме-до-бо-рі-','Й а в Лісі в Лісі й а в Медоборі
Блудили Блудці Сімсот Молодців
Приблудилися до цього Двору
До цього Двору тай Веселого

Й а в цього Ґазди двори вметені
Двори вметені столи встелені

Ой по застіллю самі Сьвятії
Самі Сьвятії тай Веселії
Бо й межи ними Одного нема
Й Одного нема - Сьвятого Різдва

Бо й Вони просять сьвятого Петра
Ти сьвятий Петре послужи Нас
Ой послужи Нас на Сяжень Землі
На Сьижінь Землі по Сьвяте Різдво!

Ой пішов Петро по Сьвяте Різдво
Його перейшло Сиве Голуб''є
Бо сьвятий Петро ся зосоломив(1)
Бо й Тому з ирта Поломінь пишла
Ой бо из очий Искри скакали

Ба й сьвятий Петро назад ся вернув
Ой він приxодить межи Сьвятії
Ти сьвятий Петре чого ся вернув
Мене перейшло Сиве Голуб''є
Ой й а того ся тай перепудив
Тому з ирта Поломінь пашет
Тому из очий Искри скакали

Ти сьвятий Петре то Сьвяте Різдво!
Ой ми устаньмо тай уклонімся
Господу Богу тай помолимся

Господу Богу Господареві
Тай уклонімся Його Ґаздині
Ой уклонімся за честь за хвалу
За честь за хвалу за гонор славу
Ба й уклонімся ще і Столові
Ще і Столові сьому Дворові
Ба й із-за хліба ба й пристайліня
Ба й із-за пиття тай доношіня

Вінчуємо Вас многа літами
Многа літами щастям-здоров''ям
Й а би Ви діждали а від сього року
Від сього року що й на другий рік
Й а у цім Домі Гості приймати
В полі вродливо в Дому щасливо
В пасіці рійно а в Дому склінно
А в Дому склінно й а в току буйно

Йа ў Лісі ў Лісі йа ў Медоборі
Блудили Блудцї Сїмсот Молодцїў
Приблудилиси ид цему Двору
До сего Двору тай Веселого

Йа ў цего Ґазди Двори Ўметені
Двори Ўметені Столи Ўстелені
Ой поза Стілю самі Сьитії
Самі Сьитії тай Веселії

Бо й мижи Ними Одного нима
Й Одного нима - Сьитого Різдва
Бо й Они просьи сьитого Петра
Ти сьитий Петре послужи Нас
Ой послужи Нас на Сьижінь Зимлї
На Сьижінь Зимлї по Сьите Різдво!

Ой пишоў Петро по Сьите Різдво
Йиго пирийшло Сиве Голубйе
Бо сьитий Петро ся зосоломив
Бо й Тому з ирта Поломінь пишла
Ой бо из очий Искри скакали

Ба й сьитий Петро назад си вернув
Ой вин приxоди межи Сьитії
Ти сьитий Петре чогос си вернув
Мене пирийшло Сиве Голубйе
Ой йа того си тай перепудив
Тому з ирта Поломінь пашет
Тому из очий Искри скакали

Ти сьитий Петре то Сьите Різдво!
Ой ми устаньмо та й уклонїм си
Господу Богу тай помолїм си
Господу Богу Господареви
Тай уклонїм си Йиго Ґаздини
Ой уклонїм си за чьист за хвалу
За чьисть за хвалу за гонор славу
Ба й уклонїм си шьи и Столови
Шьи и Столови сему Дворови
Ба й из за хліба ба й пристайлїня
Ба й из за питя тай доношіня

Вінчуйимо Вас многа лїтами
Многа лїтами шьистьом здоровйом
Йаби Ви дїждали а від сего року
Від сего року шьи й на другий рік
Йа у цїм Домі Гостї приймати
Ў полі ўродливо ў Дому шьисливо
Ў пасїцї рійно а ў Дому склінно
А ў Дому склінно йа ў току буйно','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_416185'), datetime('now')),datetime('now'));
