INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_416634','Дякую','Музика: Гурт "Океан Ельзи" Слова: Гурт "Океан Ельзи". Виконує: Гурт "Океан Ельзи"','uk','ukraine_before_1917',NULL,NULL,'Текст (основа) та аудіо (mp3): http://www.dyakyu.com/song.html','Акорди подано спрощено. Підібрано за електричною версією пісні. Деякі акорди: F7M [x 3 3 2 1 0] C* [x 3 2 0 1 3] D* [x x 4 x 3 2] D** [x x 4 x 3 5] Am/F* [x x 3 5 5 5] Em/5- [x x 2 3 x 3] G7M [x 2 0 0 3 2] Edim [x x 2 3 2 3] Замість Em/5- можна брати Edim. Аудіо (mp3) і відео до пісні є на сайті http://www.dyakyu.com/song.html:) *** Тут в аудіо текст такий: "Дякую тобі, за то, шо ти завжди зі мною..." Підбір акордів: bohdanko','Вступ:  С F7M С F7M

С          F7M          C*            D* D** D*
Дякую тобі,   за те, що ти завжди зі мною,  ***
Am/F*        Em/5-       A             D
І навіть так, як я хотів, і не без бою,
Fm                         C  F7M С F7M
але й без непотрібних слів.

Дякую тобі, за те, що ти завжди зі мною,  ***
і я живу не так як всі, як за стіною,
але з любов''ю на душі.

Програш:
C F7M C* D
Am/F* Em/5- A D
Fm C F7M С F7M

Дякую тобі, за те, що ти завжди зі мною, ***
і може й я твоє дитя, але з тобою
я світу дам нове життя.
D
...але з тобою
F7M                     C
я світу дам нове життя.

