INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4163634','Під Києвом, під Крутами','Слова: народні. Виконує: Етнографічний хор Гомін','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'аудіозапис',NULL,'Під Києвом, під Крутами     | (2)
