INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4169634','Е-е, е-е, гопа-па','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986',NULL,'Е-е, е-е, гопа-па,
Та й підемо до попа
Позичити корита.
Нема попа дома -
Поїхав по дрова,
Тільки попенята
