INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4168230','Лелеки','Музика: Михайло Герц Слова: Михайло Шушкевич','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Летіли лелеки
У вирій далекий
Із рідного краю,
Де весни цвітуть.
Де красені буки
І дивні смереки,
Де річки прозорі
У безвість течуть.

Приспів:
Лелеки, лелеки,
Близькі і далекі,
Мені ви принесли
Родинний привіт:
Пелюстки троянди,
І запах смереки,
І спогади чисті
Моїх юних літ.

Вогнем полихало,
Гриміли гармати,
З надією в небо
Дивились солдати.
Лелеки привітно
Крильми помахали,
Щасливую долю
Бійцям прокричали.

Замовкли гармати,
Прийшла Перемога,
Солдати в домівки
Вернулись свої.
І часто їм сниться
Терниста дорога,
Лелечі вітання
Й жорстокі бої.','[''pisni.org.ua'', ''cat:viyskovi'', ''Пісні на військову тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4168230'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4168230','Лелеки','Летіли лелеки
У вирій далекий
Із рідного краю,
Де весни цвітуть.
Де красені буки
І дивні смереки,
Де річки прозорі
У безвість течуть.

Приспів:
Лелеки, лелеки,
Близькі і далекі,
Мені ви принесли
Родинний привіт:
Пелюстки троянди,
І запах смереки,
І спогади чисті
Моїх юних літ.

Вогнем полихало,
Гриміли гармати,
З надією в небо
Дивились солдати.
Лелеки привітно
Крильми помахали,
Щасливую долю
Бійцям прокричали.

Замовкли гармати,
Прийшла Перемога,
Солдати в домівки
Вернулись свої.
І часто їм сниться
Терниста дорога,
Лелечі вітання
Й жорстокі бої.');
