INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_416787','Пісня про матір','(Посіяла людям...). Музика: Олександр Морозов Слова: Борис Олійник. Виконує: Раїса Цапун, Ансамбль народної музики Мереживо, Таїсія Повалій, Еріка, Оксана Нестеренко, Микола Дівін, Ірена Грех, Любомир Тарнавський','uk','ukraine_1991',NULL,NULL,'1. http://ukrlife.org/main/mother/mother_ua6.htm 2. Аудіоальбом "З піснею до матері" Р. Цапун','Варіант тексту надав Іван Вергун (гість): "Текст взятий з (інтернет-джерела), з ніяким офіційним виданням я особисто його не звіряв, тому можливі деякі неточності в тексті..." Раїса Цапун виконує пісню у супроводі ансамблю народної музики "Мереживо". Художній керівник Олександр Степанов. Текст пісні поправлений за аудіозаписом.','Посіяла людям літа свої, літечка житом,
Прибрала планету, послала стежкам споришу.
Навчила дітей, як на світі по совісті жити,
Зітхнула полегко - і тихо пішла за межу.
- Куди ж це Ви, мамо?! - сполохано кинулись діти.
- Куди ж Ви, бабусю? - онуки біжать до воріт.
- Та я недалечко... де сонце лягає спочити.
Пора мені, дітки... А ви вже без мене ростіть.
- Та як же без Вас ми?... Та що ж ви намислили, мамо?
- А хто ж нас, бабусю, у сон поведе по казках?
- А я вам лишаю всі райдуги із журавлями,
І срібло на травах, і золото на колосках.
- Не треба нам райдуг, не треба нам срібла і злота,
Аби тільки Ви нас чекали завжди край воріт.
Та ми ж переробим усю Вашу вічну роботу, -
Лишайтесь, матусю. Навіки лишайтесь. Не йдіть!
Вона посміхнулась, красива і сива, як доля,
Махнула рукою - злетіли увись рушники.
— Лишайтесь щасливі... - і стала замисленим полем
На цілу планету, на всі покоління й віки.','[''pisni.org.ua'', ''cat:pro-batkiv'', ''cat:rayisa-capun'', ''Пісні про любов до батьків'', ''Цапун Раїса: матеріали'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_416787'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_416787','Пісня про матір','Посіяла людям літа свої, літечка житом,
Прибрала планету, послала стежкам споришу.
Навчила дітей, як на світі по совісті жити,
Зітхнула полегко - і тихо пішла за межу.
- Куди ж це Ви, мамо?! - сполохано кинулись діти.
- Куди ж Ви, бабусю? - онуки біжать до воріт.
- Та я недалечко... де сонце лягає спочити.
Пора мені, дітки... А ви вже без мене ростіть.
- Та як же без Вас ми?... Та що ж ви намислили, мамо?
- А хто ж нас, бабусю, у сон поведе по казках?
- А я вам лишаю всі райдуги із журавлями,
І срібло на травах, і золото на колосках.
- Не треба нам райдуг, не треба нам срібла і злота,
Аби тільки Ви нас чекали завжди край воріт.
Та ми ж переробим усю Вашу вічну роботу, -
Лишайтесь, матусю. Навіки лишайтесь. Не йдіть!
Вона посміхнулась, красива і сива, як доля,
Махнула рукою - злетіли увись рушники.
— Лишайтесь щасливі... - і стала замисленим полем
На цілу планету, на всі покоління й віки.');
