INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4165736','Чорнобильський грім','Музика: Леонід Нечипорук Слова: Вадим Крищенко. Виконує: Павло Мрежук','uk','ukraine_1991',NULL,NULL,'Книга: Крищенко В. Д. Усі ми прагнемо любові: Пісні.-Київ:ВіРА ІНСАЙТ-2003',NULL,'Над Прип''яттю, над селами
Знов пролітають гуси,
Немов не помічаючи
Вчорашньої біди.
І побіліла матінка
Шепоче: повернуся.
Із птицями весняними
Я знов вернусь туди.
Не треба, мамо, плакати -
Життя не зупинити.
Чорнобильці, чорнобильці,
Ви гордість наша й біль.
Ми маємо, ми мусимо
Усе для вас зробити,
Щоб вам життя підносило
Щедротно хліб та сіль.

Приспів:
А чорнобильський біль, а чорнобильський біль
Ще відлунює жалем гірким звідусіль.
Ми рятуєм людей, і нам треба іти,
Де горить і пече, щоб не сталось біди.
А чорнобильський біль, планетарності грім -
Пригадати його нам потрібно усім.
Ми на чатах завжди - бачим доли і вись,
Щоб той грім на землі більше не повторивсь.

Наш рідний край карбований
Відсітинами лиха,
Не милувала доля нас
На тишу й благодать,
Та нам негоже плакати,
Сльозу роняти тихо,
А треба нам боротися
І зло перемагать.
Бо ми мобілізовані
Обов''язком і серцем,
Бо ми все пам''ятаємо,
Що забувадь не слід.
Хоча гроза Чорнобиля
В душі і не зітреться,
Та дух людської мужності
Сильніший всяких бід.

Приспів.','[''pisni.org.ua'', ''cat:chornobyl'', ''Чорнобильська катастрофа: пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4165736'), datetime('now')),datetime('now'));
