INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4169481','Ой лю-лю-лю, люлі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986',NULL,'Ой лю-лю-лю, люлі,
Налетіли гулі
Та сіли на люлі.
Стали думать ще й гадать,
Чим синочка годувать.
Годувати кашкою,
Напувати бражкою.
Що кашка добренька,
А бражка п''яненька.
Дитина маленька
Спатоньки раденька.','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4169481'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4169481','Ой лю-лю-лю, люлі','Ой лю-лю-лю, люлі,
