INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4170083','Солдатські матері','Музика: Василь Дунець Слова: Марія Баліцька. Виконує: Василь Дунець','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Виряджала мати сина:
Йди, служи, синочку мій!
Рідну землю боронити -
Це обов''язок святий!
Раптом випав серед літа
На троянди білий сніг,
Син із війська не вернувся
Вже на батьківський поріг.

Приспів:
А мати жде, а мати виглядає
Чаїно квилить мамина душа,
Тривожно серце з болю завмирає,
Пішов солдат і не сказав "Прощай!"
А мати жде, все ж вигляда синочка,
Пішов у вічність в сяйві юних літ,
Лишилась мамі вишита сорочка,
Шинеля сіра, наче моноліт.

Посивіла з горя мати,
Болем зойкнула душа,
Бо згадала як маленьким
Син навстріч їй поспішав.
Небо плакало дощами,
Гасли зорі угорі,
Носять квіти на могили
Всі солдатські матері.

Приспів.

Сину, сину мій,
Де ж ти? Де ж ти, мій синочку?

Приспів. (2)

А мати жде, все ж вигляда синочка,
А мати жде','[''pisni.org.ua'', ''cat:viyskovi'', ''Пісні на військову тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4170083'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4170083','Солдатські матері','Виряджала мати сина:
