INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4170333','Відізвись, мій Боже','Слова: о. В. Стех','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Відізвись, мій Боже милий,
Боже, правдо Ти моя!
Відізвися Ти до мене,    |
Як подам свій голос я!   | (2)

В тісноті моїй, мій Боже,
Ти давав мені простор,
І тепер мене помилуй,    |
Не віддай мене в позор.  | (2)

Бо сини людського роду
Честь мою на глум беруть,
Суєту вони злюбили       |
І неправдою живуть.      | (2)

Знайти ви, сини людськії,
Що Господь собі обрав
І сподобав сина правди,  |
Яко праведний і сам.     | (2)

І мене в моїй молитві
Він почує в небесах,
Як призву його на поміч  |
В щирих, тихих словесах. | (2)','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4170333'), datetime('now')),datetime('now'));
