INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4170131','Донечка і сонечко','Музика: Леся Горова Слова: Леся Горова. Виконує: Леся Горова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Донечко, донечко,
А де ж ховається сонечко?
За хмарки ховається,
А за землю тримається
Міцно-міцно, щоби не впало,
Щоби завтра знову встало.

Донечко, донечко,
А що робить уночі сонечко?
Та відпочиває,
На небі його немає,
Хай собі поспить
І ви його не будіть.

Донечко, донечко,
А хто ж зустрічатиме завтра сонечко?
Я зустрічатиму,
Рано-рано вставатиму,
Скаже сонечко "Привіт!"
І зрадіє цілий світ.

Донечко, донечко,
А де ж мамине сонечко?
То я, дівчинка маленька
І донечка рідненька!','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4170131'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4170131','Донечка і сонечко','Донечко, донечко,
