INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4171030','Христос воскрес! Ликуйте нині!','Слова: о. В. Стех','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Христос воскрес! Ликуйте нині,
Що в славі гроба Він повстав
Кінець приніс земній провині
І смертію Він смерть поправ.
Великдень той, то день чудес,      |
