INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4170532','Слава і честь','Слова: о. І. Луцик','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Слава і честь Тобі,
Тіло Христове!
В виді Ти хліба
На нашім престолі!
Віро, надіє,          |
Моя Ти любове,        |
Не опускай нас        |
На тій сліз юдоли.    | (2)

