INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4170236','Чужина','Музика: Микола Янченко Слова: Микола Янченко. Виконує: Іван Ганзера, Микола Янченко','uk','ukraine_before_1917',NULL,'1906',NULL,'Виконує: Микола Янченко {1906} Альбом: Моївське весілля - краще 2007','Мати доню колисала, колисала,
День і ніч у Бога долі їй благала.
Та пройшли роки так швидко, мов потоки,
Полетіла мов лебідка в світ широкий

Приспів
Чужина, чужина. Так далеко вона,
Так далеко від рідної хати.
Чужина, чужина. Там не видно вікна,
Де чекає в сльозах рідна мати.

Журавлі летять у небі, небі синім
Одиноко так без тебе всій родині.
За тобою плачуть верби на долині.
Ой не легка доля в тебе на чужині

Приспів.

Жовтий лист впаде додолу, лист багряний.
Повертайтеся до дому, Роксолани!
Вас чекає рута-мята і калина,
Вас чекає рідна мати Україна!

Приспів','[''pisni.org.ua'', ''cat:emigration'', ''Пісні про еміґрацію'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4170236'), datetime('now')),datetime('now'));
