INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4170981','Ісус з гробу увільнився','Слова: Зореслав','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Ісус з гробу увільнився,
Час смутку в радість замінився,
Адам і Єва з дітьми своїми
Грають, плешуть, скачуть з іншими всіми.
Давид у гуслі сильно вдаряє,
А хор праотців грімко співає,
Що Христос із ада душі звільняє!

Пасха всім вірним з''явилась,
Їм двері в життя відчинила.
Хай з нами буде радість із небес,
Бо Христос наш Господь із гробу воскрес,
Небо і земля, ангельські хори,
Радійте з Христом святих собори,
Увійдіть щасливі в небесні двори!','[''pisni.org.ua'', ''cat:voskresni'', ''Воскресні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4170981'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4170981','Ісус з гробу увільнився','Ісус з гробу увільнився,
Час смутку в радість замінився,
Адам і Єва з дітьми своїми
Грають, плешуть, скачуть з іншими всіми.
Давид у гуслі сильно вдаряє,
А хор праотців грімко співає,
Що Христос із ада душі звільняє!

Пасха всім вірним з''явилась,
Їм двері в життя відчинила.
Хай з нами буде радість із небес,
Бо Христос наш Господь із гробу воскрес,
Небо і земля, ангельські хори,
Радійте з Христом святих собори,
Увійдіть щасливі в небесні двори!');
