INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4171430','Божая Мати','Слова: о. В. Матюк','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свічадо, 2005. - 656 с.',NULL,'Божая Мати, чиста Дівице,
Радуйся, радуйся, наша Царицке,
Мир весь хрещений Тя прославляє,
Молиться щиро, пісні співає,
Божая Мати, Мати людей,         |
Прийми цю пісню з щирих грудей! | (2)

Тобі кланяєсь, Пречиста зоре,
Земля і небо, поле і море,
Тобі небесні хори співають,
До Тебе люди піснь посилають.
Божая Мати, Мати людей,         |
Прийми цю пісню з щирих грудей! | (2)

Краща від сонця, Діво святая,
На небі світиш, Мати благая,
Світи на працю, на хліба колос,
Учуй наш тихий молитви голос.
Божая Мати, Мати людей,         |
Прийми цю пісню з щирих грудей! | (2)

Ми к Тобі нині теж прибігаєм,
Діво Маріє, і величаєм,
Бо Ти в опіці нас завжди маєш,
Перед злом всяким охороняєш.
Божая Мати, Мати людей,         |
Прийми цю пісню з щирих грудей! | (2)

О, порятуй нас, в горю і болю,
Щастя пішли нам, дай ліпшу долю,
Праведно дай нам цей вік дожити,
З Тобою в небі Богу служити.
Божая Мати, Мати людей,         |
Прийми цю пісню з щирих грудей! | (2)','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:do-bohorodyci'', ''Церковні пісні'', ''Пісні до Богородиці'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4171430'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4171430','Божая Мати','Божая Мати, чиста Дівице,
Радуйся, радуйся, наша Царицке,
Мир весь хрещений Тя прославляє,
Молиться щиро, пісні співає,
Божая Мати, Мати людей,         |
Прийми цю пісню з щирих грудей! | (2)

Тобі кланяєсь, Пречиста зоре,
Земля і небо, поле і море,
Тобі небесні хори співають,
До Тебе люди піснь посилають.
Божая Мати, Мати людей,         |
Прийми цю пісню з щирих грудей! | (2)

Краща від сонця, Діво святая,
На небі світиш, Мати благая,
Світи на працю, на хліба колос,
Учуй наш тихий молитви голос.
Божая Мати, Мати людей,         |
Прийми цю пісню з щирих грудей! | (2)

Ми к Тобі нині теж прибігаєм,
Діво Маріє, і величаєм,
Бо Ти в опіці нас завжди маєш,
Перед злом всяким охороняєш.
Божая Мати, Мати людей,         |
Прийми цю пісню з щирих грудей! | (2)

О, порятуй нас, в горю і болю,
Щастя пішли нам, дай ліпшу долю,
Праведно дай нам цей вік дожити,
З Тобою в небі Богу служити.
Божая Мати, Мати людей,         |
Прийми цю пісню з щирих грудей! | (2)');
