INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_417131','Колиска вітру','Музика: Володимир Івасюк Слова: Богдан Стельмах. Виконує: Гурт "Океан Ельзи"','uk','ukraine_1991',NULL,NULL,'Диск MP3 формату "ОЕ"','Підбір акордів: Невідомий','Intro: Em G Em C

Em
Те джерело кришталевим б''є
G
В синіх горах дивне місце є.
Там юний вітер юність відродив
Коли гойдаються свої.

Цілу ніч я з вітром колихався
Він зі мною аж до хмар злітав
Я йому казки розповідав
Він мені свої пісні співав.

На світанку босий я іду
І додому стежки не знайду
Мене мій вітер в полі переймав
І на прощання ніжно обіймав

Цілий день із вітром ми прощались
Поки денний вечір не настав
Я йому казки розповідав
Він мені свої пісні співав.','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_417131'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_417131','Колиска вітру','Intro: Em G Em C

Em
Те джерело кришталевим б''є
G
В синіх горах дивне місце є.
Там юний вітер юність відродив
Коли гойдаються свої.

Цілу ніч я з вітром колихався
Він зі мною аж до хмар злітав
Я йому казки розповідав
Він мені свої пісні співав.

На світанку босий я іду
І додому стежки не знайду
Мене мій вітер в полі переймав
І на прощання ніжно обіймав

Цілий день із вітром ми прощались
Поки денний вечір не настав
Я йому казки розповідав
Він мені свої пісні співав.');
