INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4172634','Пісню слави заспіваймо','Слова: о. Й. Кишакевич','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Пісню слави заспіваймо
Щирим серцем нині враз,
Йосафата звеличаймо
В цей святий великий час!
Він за церкву і за віру,     |
Яу ясний борець Христа,      |
Все, що мав, приніс в офіру: |
Душу, тіло, кров, життя.     | (2)

А ми нині, браття, згідно
Злучені в любові Христа,
Господа благаймо гідно,
Щоб пролита кров свята
Посівом спасенним стала      |
Віри єдности Церков,         |
Щоб навіки всіх з''єднала     |
Під Христову хоругов!        | (2)','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4172634'), datetime('now')),datetime('now'));
