INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4170931','Пливе народ','Слова: о. Д. П.','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Пливе народ, як в морі хвилі,
З Єрусалимських всіх доріг,
І пальм гілки і квітки розцвілі
Христові кидає до ніг!

Пісні "Осанна" невгомонні
Несуться у гаї, яри,
І будять відгомони сонні
Верхи Оливної гори.

Пливе народ Христа вітати,
Пливе народ по вулицях,
На всіх обличчях усміх знати
І щиру радість ув очах.

А сам Христос жалібним зором
Журливо дивиться на них:
Ті люди завтра крикнуть хором
Вже не "Осанна", а "Розпни!"','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4170931'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4170931','Пливе народ','Пливе народ, як в морі хвилі,
З Єрусалимських всіх доріг,
І пальм гілки і квітки розцвілі
