INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4171230','Тавор-гора засіяла','Слова: о. М. Л.','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Тавор-гора засіяла,
Величіє торжество,
На ній явив Христос Господь |
Славу свого Божества.       | (2)

Там з неба зійшли пророки
Славні Іллія, Мойсей,
А Божий голос пролунав:     |
"Це Мій Син возлюблений!"   | (2)

Апостоли же Христові
Петро, Яков і Йоан,
Як узріли Христа в славі,   |
Возхитались к небесам.      | (2)

Преобразився Син Божий
І просвітився Тавор,
Його славили пророки        |
І апостольський собор.      | (2)

О, Ісусе, Спасе милий,
І ми славимо Тя всі,
Дай нам зріти свою славу    |
На всі віки в небесах!      | (2)','[''pisni.org.ua'', ''cat:christ'', ''Пісні до Ісуса Христа'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4171230'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4171230','Тавор-гора засіяла','Тавор-гора засіяла,
