INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4171333','В Єрусалимськім храмі','Слова: о. Й. Кишакевич','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'В Єрусалимськім храмі новина:
Богу на службу прийшла дитина,
Невинна, чиста, як та лелія,     |
Пренепорочна Діва Марія.         | (2)

А в храмі тихо, як серед ночі,
Чути — молитву тихо шепоче:
"Тобі служити хочу невпинно,     |
Віддати в жертву серце невинне!" | (2)

Вибрана Богом, щаслива днино,
Пренепорочна, свята дитино,
Допоможи нам серцем невинним     |
І нам служити Богу невпинно.     | (2)

Тремтять маленькі святі долоні,
Лице пречисте, наче в короні,
Дуги і сонця блиском зоріє,      |
Як в світлі сонця листки лелії.  | (2)

Допоможи нам, дитя Маріє,
Ти всьому світу вічна надіє,
Щоб ми всі разом колись в спокою |
Служили Богу вічно з Тобою.      | (2)','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:do-bohorodyci'', ''Церковні пісні'', ''Пісні до Богородиці'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4171333'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4171333','В Єрусалимськім храмі','В Єрусалимськім храмі новина:
