INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4172436','Веселися, Захаріє','Слова: о. М. Л.','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Веселися, Захаріє, днесь уже промов,
Син тобі народився, Предтеча Христов.
Від Бога тобі даний,     |
Гавриїлом предсказаний,  |
Преславний Йоан!         | (2)

Дух Святий його ще в лоні матернім святив
І понад усіх пророків вище поставив.
Христос його вихваляє    |
І ангелом називає        |
Предтечу свого.          | (2)

Радуйся, святий Йоане, Предтече Христов,
Через тебе путь Господень станеться готов.
Ти в покорі на пустині   |
Від маленької дитини     |
Свято пережив.           | (2)

У Йордані ти, Йоане, Ісуса хрестив,
Тож і Його Хрестителем зватись сподобив.
Тебе просим і благаєм,   |
Благай Бога, тя взиваєм, |
Предтече Христов.        | (2)','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4172436'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4172436','Веселися, Захаріє','Веселися, Захаріє, днесь уже промов,
Син тобі народився, Предтеча Христов.
Від Бога тобі даний,     |
Гавриїлом предсказаний,  |
Преславний Йоан!         | (2)

Дух Святий його ще в лоні матернім святив
І понад усіх пророків вище поставив.
Христос його вихваляє    |
І ангелом називає        |
Предтечу свого.          | (2)

Радуйся, святий Йоане, Предтече Христов,
Через тебе путь Господень станеться готов.
Ти в покорі на пустині   |
Від маленької дитини     |
Свято пережив.           | (2)

У Йордані ти, Йоане, Ісуса хрестив,
Тож і Його Хрестителем зватись сподобив.
Тебе просим і благаєм,   |
Благай Бога, тя взиваєм, |
Предтече Христов.        | (2)');
