INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4173434','Дощик','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май, Резонанс','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Знов на дворі дощик накрапає,
І чомусь так сумно стало всім,
Я веселу пісню заспіваю -
Може, перестане плакать він.

Приспів:
Я свої долоньки простягну до неба,
Погойдаю хмарки голубі,
Сонечко хай сяє, а дощу не треба.
Чуєш мене, дощику? - Я кажу тобі.

Кажуть під дощем ростуть малята,
Тільки мама каже навпаки
І не дозволяє нам гуляти,
Ось, чому сумують малюки.

Приспів.

Знов на дворі дощик накрапає,
І чомусь так сумно стало всім,
Я веселу пісню заспіваю -
Може, перестане плакать він.

Приспів','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4173434'), datetime('now')),datetime('now'));
