INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_41735','Жила-була царівна','(Царівна). Українська народна пісня','uk','ukraine_1991',NULL,'1998','А вже весна скресла. Збірник гаївок. Львів, 2003.','Записано 1998 року під час фольклорно-етнографічної експедиції "Джерела Божої криниці" в с. Розжалів Радехівського району Львівської області від Греви Анни. Опис гри: Усі стають у коло, беруться за руки. У середину по черзі виходять Царівна, Відьма, Царевич і виконують дії, про які співається. Кожен рядок співається, як перша строфа.','Жила-була царівна, царівна, царівна.
Жила-була царівна, царівна молода.

Царівно, бійся відьми злої... відьми злої!
Аж раз прийшла та відьма зла... відьма зла:
“Засни, царівно, на сто літ… на сто літ!”
І все заснуло твердим сном... твердим сном.
І виріс там густий бур’ян... густий бур’ян.
Аж раз прийшов царевич... царевич молодий.
Він поцілунком розбудив…царівну молоду.
І було в них весілля... весілля в них було.
І всі кричали слава... слава! (...тій парі молодій).
І були в них христини... христини в них були.
І всі кричали слава... слава тій парі молодій.
І виріс тут густий паркан... густий паркан.    Основна мелодія','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_41735'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_41735','Жила-була царівна','Жила-була царівна, царівна, царівна.
Жила-була царівна, царівна молода.

Царівно, бійся відьми злої... відьми злої!
Аж раз прийшла та відьма зла... відьма зла:
