INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_417434','Чорна кава','Музика: Ярослав Борута Слова: Михайло Тавшунський','uk','ukraine_1991',NULL,NULL,NULL,'Можна виконувати як одноосібно, так і дуетом','Є у мене нiжнi чуйнi друзi,
Як зберуться разом - цiла лава.
Довго їх тримаю у напрузi,
I себе також, та в мене кава.

Приспiв:
Чорна кава, чорна кава,
З бiлими вершками,
Я лукава, як ласкава
Iз чоловiками?

Перед тим, як пiдуть друзi з хати,
Ворожу собi та їм на кавi:
Чом нiяк не можу покохати,
Хоч є хлопцi гарнi та цiкавi.

Приспiв.

Подруги всi кажуть: "Надто горда,
Довго обираєш, наче пава."
Втiм, не кожне коло рiже хорда.
Може винна я, а може - кава.

Приспiв:
Чорна кава, чорна кава,
З бiлими вершками,
Я лукава чи ласкава
Iз чоловiками?','[''pisni.org.ua'', ''cat:romansy'', ''Романси'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_417434'), datetime('now')),datetime('now'));
