INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4175232','Летіла пава','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.137','Опр. для хору Євген Козак','1. Летіла пава, летіла, (2)
Злоте перечко згубила. (2)

2. Летіла пава без гори (2)
До свойой любой матери. (2)

3. Там єй весіля стояло, (2)
Там шість труб грало, ой, грало. (2)

4. Ой, грайте труби і баси, (2)
Згадаю дівоцькі часи. (2)

5. Грайте, гудаки, весело, (2)
Закля мій вінок над чолом. (2)

6. Як я ся вінка позбуду, (2)
Така весела не буду. (2)','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4175232'), datetime('now')),datetime('now'));
