INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4175137','Прощавай, рідна школо!','Музика: Ірина Тарнавська Слова: Ірина Тарнавська. Виконує: Маша Головатенко','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Сяду за останню парту,
Сад шумить біля вікна...
І вже згадувать не варто
Що за вікнами весна.
Ви запам''ятайте всіх нас
Тільки юними.
Ми йдемо по шляху
Сонячними струнами!

Прощавай, рідна школо,
Скільки доріг навколо,
Але я не забуду тебе!
Перший поклик кохання,
Несміливе зітхання
Знову в серці моїм оживе.

Знову чую щось малеча
Тихо-тихо так лепече,
Хтось знову кумедний дуже
Стоїть в класі у кутку,
Знову цей букварик бачу -
Все, як наяву.
Пригадаю і заплачу,
Першу вчительку свою...','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4175137'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4175137','Прощавай, рідна школо!','Сяду за останню парту,
