INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_417389','Дай же Боже в добрий час','Українська народна пісня. Виконує: Гуртоправці','uk','ukraine_1991',NULL,'2003','Ой, давно, давно.','"ГУРТОПРАВЦІ" (Гурт) - Весільні ПРИСПІВКИ "Ой чи тур чи тура", Ковельщина. Скрипки: Сергій Охрімчук – Олег Бут, бубон: Ганна Коропниченко, спів: Сусанна Карпенко, Ірина Клименко, Олена Копєйкіна, Маргарита Скаженик, Олександра Стражник, Ольга Полеха. Ой давно-давно. Найдавніша і новіша етнічна музика українців. Гурти "Древо", "Володар" і гуртоправці. Укл. Ірина Клименко (klymenko_iryna@ukr.net). 2003 Ось інші приспівки: Ой Козаче ти гуляй до себе не притуляй А як тоді гуляти як не можна тулити Ой Клим Мати Клим добре було спати з ним Буду сіно громадить щоб іще раз принадить Ой на Печі Перина на Перині Марина На Марині Миколай Боже йому помагай Ой Гриць мене тиць а я впала лежу ниць А я впала тай лежу тай нікому не скажу Ох як добра жінка гляди чоловіка Ой чужого на часок а свого довіка Еротика, жарти, забави: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... Прийди-прийди Серденя на Пухові Подушки. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні.','Дай же Боже в добрий час як у людей так і в нас
І в добрую годину звеселити родину | (2)

Ой як сват танцює черевики попсує
Ой як тиє попсує то й другиє обує  | (2)

Ой гуляще-гуляще що хороше то й наше
Що погане то не нам нехай нашим ворогам | (2)

Ой що наші вороги покопали ями
Хотіли нас повкидати попадали самі | (2)

Начихалися люди, набрехалися люде
Таки наша Ганнуся господинькою буде | (2)

Ой чи тур чи тура чи хороша Молода
Ой чи тур чи туриця чи хороша молодиця | (2)

А нашая Молода ходить тихо як вода
Хто на неї подивицця в того серце звеселицця
Хто на неї гляне в того серце в''яне

Молодий Молоду покотив по льоду
Уставай Молода бо холодна вода | (2)','[''pisni.org.ua'', ''cat:philosophic'', ''cat:vesilni'', ''Філософські пісні'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_417389'), datetime('now')),datetime('now'));
