INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4173838','Пісня першокласника','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'інтернет',NULL,'Перший раз у перший клас
Ми йдемо охоче,
Першим дзвоником для нас
Продзвенів дзвіночок.
І сміється в небесах
Сонце, як ніколи,
В мами сльози на очах - |
Я іду до школи.         | (2)

Приспів:
А у школі, а у школі
Є веселка кольорова,
І найкраща в цілім світі -
Перша вчителька моя.
А у школі, а у школі
Не сумуєм ми ніколи,
Бо учора - дошкільнята,
А тепер - одна сім''я!

Прощавайте іграшки,
Гомінкий садочок,
Кличе в класи дітлахів
Золотий дзвіночок.
І сміється в небесах
Сонце, як ніколи,
В мами сльози на очах - |
Я іду до школи.         | (2)

Приспів. (2)','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4173838'), datetime('now')),datetime('now'));
