INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4176034','Вечюр юж мі вечюр *','Українська народна пісня. Виконує: Микола Колесса, с.Ставища','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.255','Виконує: Микола Колесса {483}, с.Ставища','1. Вечюр юж мі, вечюр,
Юж мі д''вечерови,
Гонит мій миленький
Волки д''кошарови.
Гонит то він, гонит,
І батіжком стукат,
А його миленька під облачком слухат.

2. Ти, Янічку, верний,
Не черкай мі дверми,
Обийд наоколо,
Не бійся никого.
Жально мі тя, жально,
Моя мила, жально,
Же тя не виділи
Мої очка давно','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4176034'), datetime('now')),datetime('now'));
