INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4177134','Синку мій (У небесній вишині..)','Музика: Микола Свидюк Слова: О. Коненко. Виконує: Микола Свидюк','uk','ukraine_1991',NULL,NULL,NULL,NULL,'У небесній вишині
Зорі, наче очі,
Ти - мої щасливі дні
І безсонні ночі.
Смійся, синку, і нехай
Вороженьки плачуть,
Боже правий, помагай
Синові на вдачу!
Минуть зими в небуття
І літа за ними,
Синку мій, моє дитя,
Перебудим зими,
Перебудим лиховій,
Не журись, козаче,
Усміхнися, синку мій, |
Батькові на вдачу!    | (2)

Приспів:
Буде всього у житті,
Спи моя дитино,
Хай тебе усі Святі    |
Бережуть, мій сину!   | (2)

Ген від шляху до села
Дідова стежина,
Щоб вона не заросла —
Дбай про неї, сину!
Буде сонце по землі
Грати над світами -
Повертайся, синку мій,
На поріг до мами!

Приспів. (2)','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4177134'), datetime('now')),datetime('now'));
