INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4176236','Гей, був в Січі старий козак','Українська народна пісня. Виконує: Микола Будник','uk','ukraine_before_1917',NULL,NULL,'Книга:Українські народні пісні;В 2 книгах; Київ," Мистецтво" 1955; Кн.1, с.60-61',NULL,'Гей, був в Січі старий козак, на прізвище Чалий,
Вигодував сина Саву козакам на славу.
Ой не схотів же той Сава козакам служити -
Відклонився до ляшеньків в Польщу паном жити.
Гей, та схотів же той Сава слави залучити -
Став своїх батьків-запорожців по степах ловити!
Наш отаман, пан кошовий по козаках тужить:
"Ой хто б вловив того Саву, - сам йому послужить!"
"Мого сина, - каже Чалий, - ніхто з вас не вловить,
Хіба Гнатко з Кравчиною до себе підмовить!"
Наш отаман каже: "Гнатку! Як Саву не вловиш! -
Сам за нього, вражий сину, голову положиш!"
Пішов Гнатко з Кравчиною Саву підмовляти,
Як не схоче з Польщі іти, - то й смерті предати.
По дорозі стрівсь їм литвин та й став наставляти,
Як їм того пана Саву у руки піймати:
"Візьмімо сирої землі в чоботи під ноги,
А щоб не знав той пан Сава нашої підмови!"
Сидить Сава кінець столу, дрібні листи пише,
А Савиха молодая дитину колише.
Ой скінчивши дрібних листів, та й спатоньки ляже,
А щось йому під віконце: "Добривечір!" - каже.
"Піди, хлопку, піди, малий, та й уточи пива,
Нехай же ж ми та вип''ємо за здоров''я сина!
Піди, хлопку, піди, малий, та й вточи горілки,
Нехай же ж ми та вип''ємо за здоров''я жінки!
Піди, хлопку, піди, малий, та й уточи меду:
Ой щось мені нудно-трудно - голови не зведу!"
Пішов хлопець до пивниці замків відмикати, -
А козацькая старшина у двір уступати.
Не вспів хлопець, не вспів малий дійти до пивниці, -
Ускочили гайдамаки до Сави в світлицю:
"Здоров-здоров, пане Саво, здоров - як ся маєш?
Сидиш собі в світличеньці, меди попиваєш?
Далекії в тебе гості - чом же не вітаєш?"
Ой кинеться та пан Сава до ясної зброї:
"Е, ні, - кажуть, - пане Саво, се тобі не в полі!"
Ой кинеться та пан Сава до ясного меча -
Одлетіла й голівонька до самого плеча!
Не досягнув той пан Сава своєї булави -
Положили пана Саву на дубові лави:
"Оце тобі, пане Саво, сукні-адамашки,
Що ти нажив, вражий сину, з козацької ласки!"
Прилітали з України та чорні ворони -
Задзвонили пану Саві та й ув усі дзвони','[''pisni.org.ua'', ''cat:dumy'', ''cat:istorychni'', ''Думи'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4176236'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4176236','Гей, був в Січі старий козак','Гей, був в Січі старий козак, на прізвище Чалий,
