INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4175481','У неділю рано-пораненьку','(Пісня про Коваленка). Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1961','Книга:Українські народні думи та історичні пісні,Київ,"Веселка",1990,стр.118','Пісня із рукописного збірника Я.П.Новицького. Записана в 70-х рр. ХІХ ст. Друк. за вид:Історичні пісні. - 1961 - С.77-78. М.Максимович свідчить, що це зажнивна пісня часів татаро-турецьких нападів ХV-ХVІІ ст., яку часто співали волинські хлібороби. Коваленко - узагальнений поетичний образ. В одних варіантах пісні він осліплений, в інших - йому зав''язано очі. Інший варіант пісні http://www.pisni.org.ua/songs/8175474.html','У неділю рано-пораненьку
Да збирав женці Коваленко.
Ізбирав женці да все молодії,
Хлопці, дівчата все добірнії!
Ой повів женців долом-долиною
А на ту пшеницю да озимую:
"Жніте, женці, да розжинайтеся,
Да на чорну хмару не оглядайтеся.
А я піду додомоньку
Да одвідаю господоньку".
А женці жнуть да розжинаються,
Да на чорну хмару не оглядаються.
Оглянуться женці - Коваленко йде,
А позад себе орду веде;
Ведуть Коваленка та й улицею,
А зв''язали руки да сирицею.
"Утікайте, женці, куди кожний може,
Куди котрому господь допоможе!
Повій, вітре, да буйнесенький,
Да на мої женці молодесенькі!
Повій, вітре, да із Прилуки -
Чи не розв''яжуться мої білі руки;
Повій, вітре, да із півночі -
Чи не розв''яжуться мої білі очі..."','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4175481'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4175481','У неділю рано-пораненьку','У неділю рано-пораненьку
