INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4174636','Ой, сів Христос та й вечеряти','Українська народна пісня. Виконує: Микола Колесса','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.48',NULL,'Ой, сів Христос та й вечеряти,
Щедрий вечір, добрий вечір,
Добрим людям на весь вечір.

Прийшла Його Божа Мати,
Щедрий вечір, добрий вечір,
Добрим людям на весь вечір.

Ставай, Сину, рай одмикати.
Щедрий вечір, добрий вечір,
Добрим людям на весь вечір.

2. Щедрий вечир, добрий вечир (лемківська колядка)
Михайло Трохановський, с.Поляни
Антологія лемківської пісні, Львів, "Афіша", 2005, с.48

Щедрий вечир, добрий вечир,
Христа, Христа Марія,
На престолі стоява, два крижики тримава,
А ви, люде, знайте - наше право дайте!
Наше право невеличке, округліцьке,
Верчений пояс, кручений пояс.

Ще дате нам ковача, виведеме рогача.
Заб''єме му правій ріг на тот Новий рік.
Коровоньки, вовоньки, а нам ковач на щестє,
На здоровля на тот Новий рік!
Жеби ся вам родили бички-телички,
Як в лісі бучки, ялички','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4174636'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4174636','Ой, сів Христос та й вечеряти','Ой, сів Христос та й вечеряти,
