INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4177333','Ой, там на горі, ой, там на крутій','Українська народна пісня. Виконує: Древо, Гурт "Зоряна ніч", Настя Сердюк, Ансамбль пісні і танцю "Писанка", Ольга Баландюх','uk','ukraine_before_1917',NULL,NULL,NULL,'це Древо з села Крячківки. Бо ще є гурт древо у Києві.','Ой, там на горі, ой, там на крутій,
Ой, там сиділа пара голубів.       | (2)

Вони сиділи, парувалися,
Сизими крильми обнімалися.         | (2)

Десь взявся стрілець із-за крутих гір,
Розбив, розлучив пару голубів.     | (2)

Голубка не їсть, голубка не п''є
Та все ж на ту гору плакати іде.   | (2)

Голубко моя сизокрилая,
Чого ж ти такая клопітливая?..     | (2)

Та є й у мене сім пар голубів,
Лети й вибирай, можеш заміж вийти! | (2)

Я вже літала і вибирала
Немає й такого, як я втеряла...    | (2)','[''pisni.org.ua'', ''cat:lirychni'', ''cat:narodni'', ''Пісні про кохання, ліричні'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4177333'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4177333','Ой, там на горі, ой, там на крутій','Ой, там на горі, ой, там на крутій,
Ой, там сиділа пара голубів.       | (2)

Вони сиділи, парувалися,
Сизими крильми обнімалися.         | (2)

Десь взявся стрілець із-за крутих гір,
Розбив, розлучив пару голубів.     | (2)

Голубка не їсть, голубка не п''є
Та все ж на ту гору плакати іде.   | (2)

Голубко моя сизокрилая,
Чого ж ти такая клопітливая?..     | (2)

Та є й у мене сім пар голубів,
Лети й вибирай, можеш заміж вийти! | (2)

Я вже літала і вибирала
Немає й такого, як я втеряла...    | (2)');
