INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_418230','Весняночка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Весняночка-паняночка,
Де ж ти зимувала?
У садочку на кленочку,
Пряла на сорочку.

Ой сорока, ой снує,
А ворона вишиє,
А білі лебеді,
Тай відбілять по воді.

Що у тих же багачок,
Повні скрині сорочок,
А у мене одна,
Тай та чиста щодня.

Із вечора замочу,
А з півночі колочу,
А сонечко блисне,
Сорочечка висохне!

А сонечко блисне -
Сорочечка й висне,
А сонечко на південь -
Сорочечка й під рубель!

А сонечко на південь -
Сорочечка й під рубель,
А сонечко опівдні -
Сорочечка й на мені!','[''pisni.org.ua'', ''cat:narodni'', ''cat:vesnyanky-hayivky'', ''Народні пісні'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_418230'), datetime('now')),datetime('now'));
