INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4176083','Ой з-за гори чорна хмара, мов хвиля іде','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга:Українські народні думи та історичні пісні,Київ, "Веселка",1990, с.124-125','Записано в 1942 р. Фросиною Андріївною Карпенко з с.Хороше, Петропавлівського району, Дніпропетровської обл. Друк. за вид.:Українські народні думи та історичні пісні.-1955.-с.474. Пісня про Івана Богуна, одного з видатних військових керівників визвольної війни 1648-1654 рр., котрий особливо прославився в обороні Вінниці, в битвах під Берестечком, Монастирищем, у поході на Молдавію. Пізніше, під час проведення Переяславської ради, він охороняв кордони України. Відзначався винятковою сміливістю і винахідливістю. В 1664 р. був розстріляний за наказом короля Яна Казиміра.','Ой з-за гори чорна хмара, мов хвиля іде.
Тож не хмара - запорожців Богуня веде.

Доганяли вражих турків коло трьох могил,-
Уже по тих яниченьках та пугач завив.

Серед ночі в Дикім полі рушниці ревіли,
А в Очакові туркені та від страху мліли.

Ой в середу ізвечора турків обступали,
А в п''ятницю до полудня всіх упень рубали.

Ой наточив Іван Богун невірам вина,-
Та було ж їх сорок тисяч, а тепер нема','[''pisni.org.ua'', ''cat:istorychni'', ''cat:kozacki'', ''Історичні пісні'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4176083'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4176083','Ой з-за гори чорна хмара, мов хвиля іде','Ой з-за гори чорна хмара, мов хвиля іде.
