INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4182931','Не топчіть конвалій','Музика: Мирослав Скорик Слова: Ростислав Братунь. Виконує: Веселі скрипки, Тріо Либідь','uk','ukraine_1991',NULL,NULL,'Аудіозапис','Запис 60-х років із фондів радіо. Перший український твіст. Супер популярна пісня в 60-х. Також цю пісню переспівав Ігор Демарін в телециклі "Пісні серця". Кліп можна подивитись на вкладці "відео". Демарін трохи змінив 1 куплет: 1 рядок "Це маленьких дзвоників фаркунчик" 3 рядок "То весна у наступі могутнім". І в кінці повторює приспів 4 рази. Категорія:пісні до танцю Джаз,твіст','Не топчіть, не топчіть конвалій... | (3)
Не... Не топчіть конвалій...

Все в маленьких дзвониках пахучих -
Площа, вулиця, провулки, тротуари...
То весна у наступі могучім
Скинула десантом їх із хмари...

Не топчіть, не топчіть конвалій... | (3)
Не... Не топчіть конвалій...

Все змінилось, все здалось без бою:
І машини, і просто пішоходи.
Від весни ніхто не ждав розбою,
Від конвалій от такої шкоди...

Не топчіть, не топчіть конвалій... | (3)
Не... Не топчіть конвалій...

Але це було лише хвилину
І відразу все на місце стало:
Наступ конвалевий линув і відлинув
Жаль, що все це коротко так тривало...

Не топчіть, не топчіть конвалій... | (3)
Не топчіть конвалій...

Не топчіть, не топчіть конвалій... | (2)
Не топчіть конвалій...             | (2)','[''pisni.org.ua'', ''cat:dances'', ''cat:krasa-pryrody'', ''Пісні до танцю'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4182931'), datetime('now')),datetime('now'));
