INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_417685','Ой хто п’є тому наливайте (2)','(Застільна: Господь - Ненька). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'Джерело: Марко Кропивницький. ПО РЕВІЗІЇ. Етюд в 1-й дії [34 kb.] — http://library.org.ua/classic/kropiv.html: http://library.org.ua/classic/kropiv5.htm Висловлювання: Се із віку так і не у нас одних, як ділали, так і ділати будем.','Ой хто п''є  тому наливайте
