INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4180333','Гімн Інституту історичної освіти','Музика: Олександр Сироїд Слова: Олександр Сироїд. Виконує: Олександр Сироїд','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Під прапором науки і освіти
Ідем ми до майбутнього вперед,
Усі ми - драгоманівськії діти,
Хай славиться наш рідний Університет!
Студентами славетного істфаку,
Ми є і цим пишаємось завжди!
В майбутніх поколіннях, щоб плекати
Любов до української землі.

Приспів:
Істфак, вперед!
Через терни до зірок!
Істфак, вперед!
До мети нам тільки крок!
Один лиш крок!

Історія - то наша рідна мати,
А батько - наш славний факультет.
Пройдем крізь час, щоб істину пізнати,
Розкриємо минулого секрет.
Вперед йдемо дружнім колективом,
Щоб велич України піднести,
Для цього покладем ми усі сили
Й будь-що не відступимось мети!

Приспів.

Під прапором науки і освіти
Ідем ми до майбутнього вперед,
Усі ми - драгоманівськії діти,
Хай славиться наш рідний Університет!','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4180333'), datetime('now')),datetime('now'));
