INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_418030','Не бійся жити','Музика: Марія Бурмака Слова: Марія Бурмака. Виконує: Марія Бурмака','uk','ukraine_1991',NULL,NULL,'Аудіо-CD "Марія Бурмака. "№9" (2004)','Текст виправлено за аудіо-записом. Акорди записано на слух з аудіо-запису. Оригінальна тональність: Gm. * Тут, можливо, інакше: "Світ для того, щоб любити тебе." Підбір акордів: bohdanko (www.pisni.org.ua)','Вступ:  F#m D A E (x4)

І коли залишилася зовсім сама,
І коли вже здається — світла нема,
Коли небо твоє на колір чужим стає,
Ти б виводила лінії знов на руці,
Впізнавала б надію в кожнім лиці,
Малювала б на склі вогонь —
І розбила б скло.

Приспів:
Не бійся жити — світ для того, щоб любити,
Сонце, дощ і вітер,
Небо, зорі, квіти... Все для тебе,
F#m
А ти не бійся жити,
Сонце, дощ і вітер,
E
Небо, зорі, квіти,
Всі для того, щоб любити тебе.

Програш:  F#m D A E (x2)

Ти ішла по межі,
Ти ішов по межі,
Тільки знай: ніхто тобі не чужий,
І рука у руці — назавжди твоє тепло.
І не можеш тепер лишитися сам,
Де читаєш мої слова по губам,
Повертає тебе назад моя любов.

Приспів.

Ти у серці своїм — тамований стук,
Ти на дотик, як спалах, навіть на звук,
Ти вже майже летиш — відкрите вікно давно.
Розбивається ніч, ламається час,
Ти гасила вогонь — не згасла свіча,
І не бійся — любов тепер береже тебе.

Приспів.  (x2) ...','[''pisni.org.ua'', ''cat:philosophic'', ''cat:suspilno-politychni'', ''Філософські пісні'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_418030'), datetime('now')),datetime('now'));
