INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4182034','Лісові генерали','Музика: Олександр Смик Слова: Олександр Смик. Виконує: Володимир Вермінський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'По незбираних яблуках, по нескошених травах
Утікали до лісу від зради затравлені
І палали під небом свічі кинутих хат,
За молодшого брата ішов старший брат.

Приспів:
Лісові генерали наділив Бог сповна,
Вистачало звитяги, відваги і честі.
Лісові генерали, та життя ж - не війна,
Озирніться довкола - скільки спалених весен!

А коли за край неба позлітались круки
І жінки голосили, залишившись з синами,
Вишиванки топтали москалі-яструбки
І везли сім''ї їх до Сибіру возами.

Приспів.

Виростали сини - люті діти війни,
Тим снігам, таборам у продовженні сниться
Хтось на білім коні, хтось на тім воронім
Досі скачуть і годі спиниться!

Приспів. (2)

Озирніться довкола - скільки спалених весен...','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4182034'), datetime('now')),datetime('now'));
