INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4182838','Якби на річку покласти кладку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Якби на річку покласти кладку,
І через неї перейти.
Якби забути щире кохання,
І до дівчини більш не йти.

Ой знаю, занаю Ти мій миленький,
Що Ти аж трьох нас полюбив.
Тільки не знаю Ти мій миленький,
Котру на серці залишив.

Одну любив я за карі очі,
Другу любив за красоту.
А тая третя сумна ходила,
Лишилась в серці моєму.

Ой вийшла мила на крутий берег,
Там де плавають кораблі.
Скочила вводу згубила вроду,
Знайшла притулочок собі.

За нею милий на крутий берег,
Там де плавають кораблі.
Вийняв хустину кинув на воду,
Візьми миленька - це Тобі.

Візьми миленька зав''яжи рану,
Щоб не розмила її вода.
Ті  карі очі, той стан дівочий,
Що нахилився вже до дна.

І став дрібненький дощ накрапати,
Висока хвиля виграва.
Усі дівчата гуляють в парі,
Моєї милої нема.

І вже на річку поклали кладку,
Я через річку перейшов.
Я не забув те щире кохання,
Хоч до дівчини більш не йшов.    Аматорський','[''pisni.org.ua'', ''cat:lirychni'', ''cat:narodni'', ''Пісні про кохання, ліричні'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4182838'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4182838','Якби на річку покласти кладку','Якби на річку покласти кладку,
І через неї перейти.
Якби забути щире кохання,
