INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4183736','Стрийський парк','Музика: Євген Козак Слова: Ростислав Братунь. Виконує: Маріанна Винницька','uk','ukraine_1991',NULL,NULL,'Аудіозапис',NULL,'Кілька вулиць нас розділяє
Та розлуки довгої літа,
Стали болем стали відчаєм,
Наче скеля кам''яна крута...
В місті одному ми,
А чужі назавжди...
Але я кохаю і чекаю,
Зву тебе: Прийди!..

Приспів:
Стрийський парк в осінні тихі дні
Нагадує мені давноминуле щастя...
Стрийський парк нагадує ті дні,
Які вже не вернеш, вернуть не вдасться...
І шепіт вітру в старих алеях парку
Не говорив нам, що промине любов...
Стрийський парк, пливуть за днями дні,
І тужно так одній, бо ти не прийдеш знов...

Я сьогодні тебе зустріла,
Ти у парку сам собі блукав.
А мені здавалось на крилах
Ти до мене знову поспішав...
Он, як хоч би у сні,
Як в ті далекі дні,
Щоб тебе зустріти полонити
Назавжди мені...

Приспів.

І шепіт вітру в старих алеях парку
Не говорив нам, що промине любов...
Стрийський парк, пливуть за днями дні,
І тужно так одній, бо ти не прийдеш знов...
Бо ти не прийдеш знов...','[''pisni.org.ua'', ''cat:dances'', ''cat:tango'', ''Пісні до танцю'', ''Танґо'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4183736'), datetime('now')),datetime('now'));
