INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4185034','Вулицею йдем, Купайло несем','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256','Опис: Дівчата приносили на місце гуляння У-подібне Купайло, а молодиці робили для дітей "купайлиці" — щось на зразок довгого качана з квітів і вишень.','Вулицею йдем,     |
Купайло несем.    | (2)

Наше Купайло      |
У лісі було.      | (2)

Ми його знайшли,  |
В село принесли.  | (2)

А ви, дівочки,    |
Плетіть віночки.  | (2)

Ви, молодиці, -   |
По купайлиці.     | (2)

А ви, бабусі,     |
Збирайтеся всі.   | (2)

Хлопці, дивіться  |
Та й не казіться! | (2)','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4185034'), datetime('now')),datetime('now'));
