INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4184338','Шум','(Ой, нумо, нумо зеленого Шума). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256 с.',NULL,'Ой, нумо, нумо зеленого Шума,
Шума заплетемо - гуляти підемо.

Ой, Шум ходить, по воді бродить,
А Шумиха рибу ловить.

Що зловили - те й пропили,
Дочці шуби не купили.

Пожди, доню, до суботи,
Буде шуба ще й чоботи.

Субота минає - а шуби немає,
А Шумиха із Шумом гуляє.

Пожди, доню, до неділі,
Буде шуба й фартух білий.

Неділя минає - а шуби немає,
А Шумиха із Шумом гуляє.

Пожди, доню, до вівторка -
Буде шуба ще й шнуровка.

Вівторок минає - а шуби немає,
А Шумиха із Шумом гуляє.

Пожди, доню, до середи,
Буде шуба ще й переди.

Середа минає - а шуби немає,
А Шумиха із Шумом гуляє.

Пожди, доню, до п''ятниці,
Буде шуба ще й спідниця...','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4184338'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4184338','Шум','Ой, нумо, нумо зеленого Шума,
Шума заплетемо - гуляти підемо.

Ой, Шум ходить, по воді бродить,
А Шумиха рибу ловить.

