INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4187735','Цей новий рік','Музика: Ігор Рудий Слова: Оксана Голуб. Виконує: Іван Красовський, Оксана Голуб, Ігор Рудий, Владислав Лєлюшкін','uk','ukraine_before_1917',NULL,NULL,'Продюсер',NULL,'Світять вогнів герлянди.
Ясно, неначе вдень.
В місті сьогодні свято,
Свято в серцях людей!
Рідні прийдуть, знайомі.
Їх зутрічати час.
В кожнім гостиннім домі
Радо чекають вас.

Приспів:
Новий рік!
Хай подарує нам Новий рік
Безліч думок і заповітних мрій!
Новий рік!
Хай буде чистим цей новий рік,
Мов той найперший білий,
Сріблястий сніг!

Казку чекають діти,
Чути веселий сміх!
Нам вже не зрозуміти
Мрій всіх дитячих їх.
Та у цю ніч дитинство
Ближчим стає для всіх.
Мить чарівного дійства -
Відлік хвилин нових.

Приспів','[''pisni.org.ua'', ''cat:socialno-pobutovi'', ''Соціально-побутові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4187735'), datetime('now')),datetime('now'));
