INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4185131','На Купала була, сорочку забула','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'На Купала була,
Сорочку забула.
Купала на Йвана!

Не піду додому -
Боюся сорому.
Купала на Йвана!

Загорнусь в солому
Та й піду додому.
Купала на Йвана!

Вітер налітає -
Солому зриває.
Купала на Йвана!

А слідом за мною
Хлопці чередою.
Купала на Йвана!
* * *
Купало, Купало,
Чи ти з неба впало,
Купала на Йвана!

Чи з землі взялося,
Що таке вдалося?
Купала на Йвана!','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4185131'), datetime('now')),datetime('now'));
