INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4184436','Огірочки','(Ой, питалася мати дочки). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256 с.','Опис гри: Молодь стає в ряд, узявшись за руки. Крайня з одного кінця пара підносить зімкнені руки догори — робить ворота. Крайній з другого кінця учасник гри веде усіх за собою крізь ті ворота, немов би затягуючи петлю. При цьому другий з "воріт" учасник має стати "заплетений": рука, що утворювала ворота, має лягти на власне протилежне плече; далі друга рука підноситься догори і утворює наступні ворота спільно з наступним учасником. Коли всі учасники гри стають "заплетені", той самий крайній "розплітає" їх у зворотньому порядку.','Ой, питалася мати дочки:
Де посієм огірочки?
Най ся в''ють.        | (2)

Ой, посієм над водою,
Заскородим бороною,
Най ся в''ють.        | (2)

Ой, сіяли, поливали,
Бо ся гості сподівали.
Най ся в''ють.        | (2)

Ой, вийтеся, огірочки,
У зелені пуп''яночки,
Не рвіться.          | (2)
Чи великі, чи маленькі
В''яжіться.           | (2)

Ой, буду вас поливати,
Щосуботи вибирати -
Не рвіться.          | (2)
Чи великі, чи маленькі -
В''яжіться.           | (2)

Ой, приходьте, парубочки,
Вибирати огірочки -
То ж ся в''ють.       | (2)

Ой, приходьте, сусідочки,
Вибирати огірочки -
То ж ся в''ють.       | (2)

Ой, позичте, кумко, бочки -
Най наквашу огірочки,
То ж ся в''ють.       | (2)

Не позичу, кумко, бочки —
Маю свої огірочки,
То ж ся в''ють.       | (2)

Огірочки зелененькі,
Завивайтеся, завивайтеся!

Ви, дівчата, молоденькі,
Віддавайтеся, віддавайтеся!

А ви, хлопці молоденькі,
Женихайтеся, женихайтеся!

А которі жовтяки -   |
Так то наші парубки! | (2)','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4184436'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4184436','Огірочки','Ой, питалася мати дочки:
