INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4185236','Ой на морі утя та й купалося','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'Ой на морі утя
Та й купалося,
А на бережечку
Та й сушило(ся).

А на бережечку
Та й сушилося,
А на мене мати
Та й сварила(ся).

А на мене мати
Та й сварилася,
Щоб я на юлиці
Не барила(ся).

Ой, як будеш, мати,
Та й сваритися,
Буду на юлиці
Та й барити(ся).

Ой, як будеш, мати,
Та й докучати,
Буду на юлиці
Та й ночува(ти)!','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4185236'), datetime('now')),datetime('now'));
