INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4184838','Стоїть над Волгою курган','Музика: Ігор Шамо Слова: Дмитро Луценко','uk','ukraine_1991',NULL,NULL,'Дмитро Луценко "Усе любов''ю зміряне до дна", Київ, видавництво "Криниця", 2005',NULL,'Стоїть на Волгою курган,
Шумить густими полинами.
І сивий стелиться туман
В степу над вбитими синами.
Вітри їх в синю даль зовуть,
Багряний ранок мружить вії.
І роси падають в траву,
Гарячі роси падають в траву,
Як сльози матері святії.

Ішли в шинелях юнаки
З Тамбова, Києва і Тули.
В боях важких біля ріки
В кургані волзькому заснули.
Вітри їх в синю даль зовуть,
Багряний ранок мружить вії.
І роси падають в траву,
Гарячі роси падають в траву,
Як сльози матері святії.

Затих над степом ураган,
Гримлять лиш в спогадах гармати.
Стоїть край берега курган,
І в ньому сплять брати-солдати.
Вітри їх в синю даль зовуть,
Шумлять, як втрачені надії.
І роси падають в траву,
Гарячі роси падають в траву,
Як сльози матері святії.','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4184838'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4184838','Стоїть над Волгою курган','Стоїть на Волгою курган,
