INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4186583','Летіла зозуля','Українська народна пісня. Виконує: Ніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Летіла зозуля
З гори та в долину
Та й сіла кувати    |
Коло мого тину.     | (2)

Зозуле, зозуле,
Десь ти горе чуєш,
Коло моєй хати      |
На калині куєш?..   | (2)

Зозуля кувала,
Правдоньку сказала,
Що моєї неньки
На світі не стало.

Добігла до хати,
Стала на порозі,
Забилось серденько, |
Покотилось сльози.  | (2)

Ой, матінко-мати,
Де тебе узяти?..
Чи піти купити,     |
Чи намалювати?..    | (2)

Наїхали маляри
З далекой сторони,
Змалювали неньку    |
На білій оселі.     | (2)

Змалювали очі,
Змалювали броди,
Та не змалювали     |
Щирої розмови...    | (2)','[''pisni.org.ua'', ''cat:narodni'', ''cat:nostalgia'', ''cat:pro-batkiv'', ''Народні пісні'', ''Пісні з ностальгічними мотивами'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4186583'), datetime('now')),datetime('now'));
