INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4188434','Пробач мені, мамо','Українська народна пісня. Виконує: Берники','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Мені ти вказала до неба дорогу,
Маленьким дитятком до Бога вела.
Чому, моя мамо, для тебе так рано
Настала осіння пора?..

Приспів:
Пробач мені, мамо,
За те, що так рано
Збіліла твоя голова.
Тебе я кохаю,
Без тебе, не знаю,
Як жить на землі буду я...

Не знаєш ти втоми, хоч інколи ноги
Підкосить, як серпом траву,
Не чуєш ти болю, хоч руки в мозолях,
І стримують очі сльозу...

