INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4192030','Вгору прапори','Музика: П.Білецький Слова: Леонід Полтава','uk','ukr_ssr_1919_1991',NULL,'1925','www.cym.org/ua','Інформації про існування організаційного гімну в СУМі 1925-1929 років немає. Уже в 1940-х роках, в діаспорі з''являються перші спроби укласти сумівський гімн, зокрема відомо про використання під час церемоніалу пісні "Гей струнко стань, на прапор глянь". Втім, у 1960-х роках ЦК СУМ оголосив конкурс на кращі слова тексту на сумівський гімн. Найбільшу прихильність здобув текст написаний у 1964 році відомим письменником, публіцистом та поетом Леонідом Полтавою, який в той час був головним редактором сумівського журналу "Крилаті". Музику до тексту Л.Полтави "Вгору прапори" уклав П.Білецький.','Вгору прапори слухай наказ:
Де б не прийшлося нам жити,
Більшого щастя нема для нас
Як Україні служити!

Гартуйсь! Гартуйся! Зміно молода!
Гуде земля від нашої ходи!
Солод-солодка у Дніпрі вода
Ми нап''ємось Дніпрової води.

Вгору прапори, вгору серця!
Гордо несім нашу славу,
Нині сумівця, завтра бійця
За Українську державу!

Гартуйсь! Гартуйся! Зміно молода!
Гуде земля від нашої ходи!
Солод-солодка у Дніпрі вода
Ми нап''ємось Дніпрової води.','[''pisni.org.ua'', ''cat:himny-marshi'', ''Гимни та марші'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4192030'), datetime('now')),datetime('now'));
