INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_418583','А вже Весна скресла (2)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Гаїлки-Великдень: Українське свято Відродження Світа. Вже Весна воскресла: Принесла вам Красу Господарську Рясу. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... РОЗСПІВ: А вже Вес-на скрес-ла скрес-ла Що Ти нам при-нес-ла |(2) Приспів: Гей Дів-ча-та Вес-на Крас-на Зіл-ля Зе-ле-нень-ке Вже Весна воскресла. Весна іде Красу несе і тій Красі радіє все. Українська Астральна релігія: Великодні Паски. Але замітне є в Українській Астральній реліґії окреме поєднання культових об''єктів, а саме: шанування Місяця і Зорі з виключенням Сонця. Завважимо також у символіці, стосованій до Святочного печива, як найвиразніше зазначуване шанування Місяця і Зорі (у двійку). Так приміром я бачив (у Конюхах, Бережани) Великодні Паски, на яких посередині була вироблена з тіста, артистичними півкругами, велика восьмикінчаста Зоря (ассирійська восьмираменна звізда!), а по чотирьох рогах доокола Зорі були зображення Місяця, очевидно 4-х його фаз у подобі чотирьох вужиків. (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Висловлювання: При своїм ріднім. Ягілки (гагілки, галагілки, гаївки, веснянки) – це обрядові пісні Українського народа, сягаючі своєю давниною непам''ятних часів. Є вони головною основою найбільшого свята Воскресення Весни-Літа. Природа, її зміни і сили викликували в народі божеське почитання. Свята, получені все з всенародними забавами-ігрищами, були в честь лише добрих богів – добрих сил природи. Це вкорінене в народі вірування в добрі і певні переміни сил природи, в сильних добрих богів, що дають світло, тепло, дощик і оживлюють плодовиту землю, перетривало довгі віки. Християнство, що достроїлося... до давніх звичаїв, не змогло і доси вируґувати зовсім цього дохристиянського вірування, цього обожання природи, і народ ще доси в більшості має більше розуміння і прив''язання до предківських переконань, ніж до християнських незрозумілих і неприступних засад. Ще нині є околиці, — не лише на Поліссі, — де народ не розуміє майже християнства і не старається зрозуміти, а живе в переконаннях дохристиянських наших предків. Народ... не дається легко переконувати, хіба, що сам наглядно переконається. Цьому завдячуємо, що наша народна давнина не затратилася, хочай її і чужі і свої завзято викорінювали як "бісовскія плясанія". Весняне Свято було також важним для молодих, головно із-за вільного запізнавання. Було воно в дохристиянських часах рівнож Святом загальних заручин. А вже Весільні обряди відбувалися внедовзі по Святах. Простолюдин і тепер Весільні обряди більше вважає потрібними для важности шлюбу, як церковні церемонії. Обов''язком свідомих Українців повинно бути не дати ніяк загинути цьому гарному звичаєві, тому нашому заборолові, яке держить народ кріпко при своїм ріднім. Де нема Веснянок, треба покласти собі за ціль вивчити молодіж Ягілок, а коли вони раз приймуться, то вже їх ніхто не викорінить. Богато зібраних мною пісень та етноґрафічних записок забрала мені польська дефензива при богатьох ревізіях і відібрати їх ніяк не можна. Жаден уряд в Польщі не знає, де поділися річи забрані при ревізіях. (М. Миханько. "Ґенеза Ягілок", Львів 1922 — Ню Йорк 1966) Висловлювання: Прийшов час спитати. Даю вам так багато, а ви берете так мало. — І ще сказано: Великі багатства дано вам. Прийшов час спитати, як ви їх берегли і помножили. (З життя Спасителя: Добрі Новини) Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа Стежки до листків про Українські традиції.','F
