INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_418838','Іди від мене','Музика: народна Слова: Яр Славутич. Виконує: Не журись!, невідомий','uk','ukr_ssr_1919_1991',NULL,NULL,'1. Туристський пісенник "Де гори Карпати, де Писаний камінь". - Літо, 1982. 2. Пісневир. Молодіжний співаник. - Львів, 2001.','У джерелі [1] відсутня третя в''язка. Не раз чув хибне виконання під мелодію "Широка страна моя родная..." Акорди (варіант 2) надав Taras Hryvul. Можливо, автором музики є А. Гнатишин (джерело: Taras Hryvul).','Іди від мене ти, моя кохана
Зійди з очей, мене не забувай;
Я син лісів, а серце партизана,     |
C7A7         Dm    |(2)
На мене жде з побідою ввесь край.   |

Надармо ти надією палаєш,
Щоби мене до серця пригортать.
Та ти сама це дуже добре знаєш,     |
Що партизанам тільки воювать.       |(2)

Сьогодні нас Карпати зустрічають,
А завтра, знай, Волинь вітає нас,
Відтак підемо прямо аж на Київ,     |
Полтаву, Харків, рідний нам Донбас. |(2)

І увесь час ми чайкою літаєм,
Із лісу в степ широкий ми ідем;
Ми свято вірим в нашу перемогу,     |
Що Україні волю принесем.           |(2)
Акорди (варіант 2):
Іди від мене ти, моя кохана
Зійди з очей, мене не забувай;
Я син лісів, а серце партизана,     |
На мене жде з побідою ввесь край.   |','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_418838'), datetime('now')),datetime('now'));
