INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_418889','Незалежний рок-н-рол','(Пролетарський рок-н-рол). Музика: Анатолій Сухий Слова: Анатолій Сухий. Виконує: Рутенія','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Шовіністичний Харків
І гоноровий Львів,
І благородний Київ
Рок-н-рол для вас зробив!

Рок-н-рол, рок-н-рол,
Не той тепер вже Миргород,
Не той тепер Хорол, -
Танцюють хлопці
Миргородський рок-н-рол!

Вчора в мене негри
Мою милу вкрали,
Та я на них не злюся,
Бо вони не знали,
Що я танцюю рок-н-рол,
Що я танцюю рок-н-рол,
Що я танцюю справжній рок-н-рол!

Любі київляни
Й недавні селюки,
Що стали вже киянами
З легкої руки,
У цю важку годину
Дарує вам Хорол
Перлину України -
Полтавський рок-н-рол!

Мальчікі і дєвочкі,
Хлопчики й дівчатка
Ви тільки не волнуйтеся,
Бо то ще не початок,
То ще не початок,
То ще не причина, -
Рок-н-рол зробила Галичина!

Вчора був Штефан,
А нині вже Іван,
А завтра Іван
Збере чемодан,
Поїде в Магадан. -
Гуд бай Іван,
Хай живе Штефан,
Гордість галичан!

Гей ви хлопці-буковинці,
Буковинці молодії,
Беріть в руки паляниці,
Бо вже їдуть......
Ой, боже ж мій милий,
......... німці!

Мальчікі і дєвочкі,
Хлопчики й дівчатка
Ви тільки не волнуйтеся,
Бо то ще не початок,
Бо для нас,
Бо для вас
Рок-н-рол зробив Донбас!

Вчора було їсти,
Сєгодня вже нема, -
Прокляті екстремісти, -
Страдаєт вся страна, -
Центр масс на себя берьот Донбасс,
Центр масс на себя берьот Донбасс,
Центр масс всех масс - Донбасс!

Мальчікі і дєвочкі,
Хлопчики й дівчатка
Ви тільки не волнуйтеся,
Бо то ще не початок,

Не той тепер вже Миргород,
Не той тепер Хорол, -
Танцюють хлопці
Справжній рок-н-рол!
Танцюють немосковський,
Танцюють незалежний,
Танцюють самостійний рок-н-рол!

* Швидка абракадабра','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_418889'), datetime('now')),datetime('now'));
