INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4189287','Сонце сходить і заходить','Українська народна пісня. Виконує: Остап Стахів','uk','ukr_ssr_1919_1991',NULL,NULL,NULL,NULL,'Сонце сходить і заходить,
А в тюрмі моїй темно,
Дні і ночі вартовії      |
Стережуть моє вікно.     | (2)

Не стережіть, вороженьки,
Тут нелегко утекти,
Ті кайдани залізнії,     |
Нелегко їх пірвати.      | (2)

Ті кайдани залізнії,
Ще й до того сталеві,
Не пірвуть вас мої руки, |
Не поріжуть вас ножі.    | (2)

А ви, пташки-канарейки,
Підлітайте високо,
Перекажіть на Вкраїну,   |
Що я в тюрмі далеко.     | (2)

А ви, пташки-канарейки,
Підлітайте ще вище,
Перекажіть на Вкраїну,   |
Що я в тюрмі ще дальше.  | (2)','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4189287'), datetime('now')),datetime('now'));
