INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4192636','Із-за хмари','Українська народна пісня. Виконує: Кумасеньки','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Із-за хмари з-за туману
Срібний місяць випливає!
Щедрий вечір, добрий вечір!

Добрий вечір, добрі люди,
Хай вам щастя завжди буде!
Щедрий вечір, добрий вечір!

Прийшли хлопці і дівчата
З Новим роком вас вітати!
Щедрий вечір, добрий вечір!

З Новим роком вас вітаєм,
Щастя й радості бажаєм!
Щедрий вечір, добрий вечір!

Хай лунає пісня щира,
Пісня щастя, дружби й миру!
Щедрий вечір, добрий вечір!

Щедрий вечір, добрий вечір!','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4192636'), datetime('now')),datetime('now'));
