INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4186636','А на добрий вечір','Українська народна пісня. Виконує: Ніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'А на добрий вечір,
Пане господарю, до тебе.
Кличе ті Господь
На порадоньку до себе!
Обіцяв ті Господь
Золоті пшениці зродити,
Дай же ті, Боже,
Щастя, здоровля спожити.

А на добрий вечір,
Пане господарю, до тебе.
Кличе ті Господь
На порадоньку до себе!
Обіцяв ті Господь
Сто порцій вівса зродити,
Дай же ті, Боже,
Щастя, здоровля спожити.

А на добрий вечір,
Милиє панство, слухайте.
Кличе вас Господь
На порадоньку до себе!
Обіцяв вам Господь
Дві бочки щастя зродити,
Дай же вам же розуму,
Втіхи й здоровля розподілити.

Щедрий вечір! Добрий вечір!','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4186636'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_4186636','А на добрий вечір','А на добрий вечір,
Пане господарю, до тебе.
Кличе ті Господь
На порадоньку до себе!
Обіцяв ті Господь
Золоті пшениці зродити,
Дай же ті, Боже,
Щастя, здоровля спожити.

А на добрий вечір,
Пане господарю, до тебе.
Кличе ті Господь
На порадоньку до себе!
Обіцяв ті Господь
Сто порцій вівса зродити,
Дай же ті, Боже,
Щастя, здоровля спожити.

А на добрий вечір,
Милиє панство, слухайте.
Кличе вас Господь
На порадоньку до себе!
Обіцяв вам Господь
Дві бочки щастя зродити,
Дай же вам же розуму,
Втіхи й здоровля розподілити.

Щедрий вечір! Добрий вечір!');
