INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4193787','Новий рік','Музика: Анатолій Зубков Слова: Сергій Сашин. Виконує: Наталі Мартін','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Рік старий закінчує свій біг,
На годинниках мовчать секунди,
І летить пухнастий білий сніг
А над містом зоряні салюти.
Загадай бажання у цю ніч,
Загляни на мит в своє майбутнє,
І повір у чудо незабутнє,
Щастя лине і дитячий сміх.

Приспів:
Новий Рік! -               |
Завжди солодкий сон!       |
Новий Рік співає в унісон, |
Новий Рік запалює серця,   |
В наших душах казка ожива! | (2)

Новорічний Дід дарує знов
Подарунки і веселі тости,
На ялиночках горять вогні,
Хай здорові будуть ваші гості.
Хай здійсняє мрії Новий рік,
Хай уся родина процвітає!
Вам бажаю радості і мрій
І сердечно щиро всіх вітаю!

Приспів.

З Новим Роком! З Новим Роком!
З Новим Роком! З Новим Роком!

Приспів.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4193787'), datetime('now')),datetime('now'));
