INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_419338','Ой, як же було ізпрежди віка','Українська народна пісня. Виконує: Олег Скрипка, Ані Лорак','uk','ukraine_before_1917',NULL,NULL,NULL,'Фінальна пісня мюзиклу "Вечори на хуторі біля Диканьки". Виконують Олег Скрипка та Ані Лорак','Ой, як же було ізпрежди віка
Ой, дай Бог.
А тільки було синєє море
Ой, дай Бог.
Ради радоньку, кого в море послать
Ой, дай Бог.

Зачарована, сумна засинає далина у неба на руках.
Ми на безері ріки, бьються хвилями роки,
То є ріка життя.
Понад берігом іде, але хто її знайде
І хто згадає знов?
Світ коли не було нас,
Але ангел в перший раз
Подарував любов.

А тільки було синєє море
Ой, дай Бог.
Ради радоньку, кого в море послать
Ой, дай Бог.

Ми не янголи святі, але струни золоті
У душах не мовчать.
Про кохання і вогонь, що бажаємо його
Співає нам печаль.
Доля згадує про нас
І на скронях сивина, неначе білий сніг.
І віків старовина, наче пісня неземна
Приходить у вісні.

А тільки було синєє море
Ой, дай Бог.
Ради радоньку, кого в море послать
Ой, дай Бог.','[''pisni.org.ua'', ''cat:lirychni'', ''cat:narodni'', ''Пісні про кохання, ліричні'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_419338'), datetime('now')),datetime('now'));
