INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4194236','Ой, зима, зима','Музика: Микола Мозговий Слова: Андрій Демиденко. Виконує: Іван Попович, Ольга Макаренко','uk','ukraine_1991',NULL,NULL,'http://ledi-di.ucoz.ua/load/do_zimovikh_svjat/oj_prijshla_zima/12-1-0-239#',NULL,'Ой, пішла зима в танок, вітром дунула в ріжок
Заплела узори нам на вікнах
Із небесного млина сипле борошно сповна
Стелить синє полотно на ріках.

Приспів:
Ой, зима ти білочола,
Білі пера, білі грона
Ти уся як ружа біла
І хмільна, немов весілля.

Не знайти стежок-доріг, скрізь як пух сріблиться сніг
Всюди білі-білі самоцвіти
Тільки полум''я калин та заграви горобин
Та червоні снігурі, мов квіти.

Приспів:

В''ється паморозь як хміль, гра на скрипці заметіль
В білі сукні вбрала ліс і лози
Місить дивнії коржі в кришталевій ох діжі
Наливає в келихи морози.','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4194236'), datetime('now')),datetime('now'));
