INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4192230','Дивная зірка','Музика: Зоя Красуляк Слова: Зоя Красуляк. Виконує: Наталя Мельник','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Дивная зірка в небі світила,
Діва Марія Дитя народила,
Зраділи люди, весь світ звеселився,
У Вифлеємі Христос народився!

Ангели пісню величну співали,
Діва Марія Дитя сповивала,
Із пастушками вівці й ягнятка
Радо витали маленьке Дитятко!

Царі зі Сходу в дорогу рушали,
Божому Сину дари складали,
У кожній хаті, кожній родині
Раділи люди маленькій Дитині!

Дивная зірка в небі сіяла -
Христос родився! - усім сповіщала,
Радуйся, земле, велике нам свято,
Христос родився, щоб світ врятувати!','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:shchedrivky'', ''cat:suchasni-pisni-rizdvo'', ''Колядки'', ''Щедрівки'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4192230'), datetime('now')),datetime('now'));
