INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4194632','Пісня про матусю','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Як добре, що у мене матуся рідна є,
Вона мене голубить і жаліє,
І знов весна приходить, і сонечко встає,
Бо так любити тільки мама вміє.
До мами пригорнуся, неначе пташеня,
Люблю тебе, матусенько моя!

