INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_4195134','Ти, Йордане, приготовися',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ти, Йордане, приготовися,
А ти, Йоане, скоро спішися
З Діви Марії хрестити сина,
Бога Слова в Тройці єдина
Во річних струях.

Йордан жахнувся і стрепенувся,
І біг у бистру назад вернувся.
Цю святу хвилю, хвилю велику
Розп''яття серця спасай Владико,
Ласк твоїх сей день.

Вже облак ясний світить дугою,
Вже йде хрестити Христос водою.
Радій, Йоане, тішся, Йордане,
Це ж Христос Господь за хвилю стане
У водах твоїх.

Загримів громом облак голубий,
Озвався голос: "Це син мій любий",
Так довгожданний для всіх народів,
Одно спасення для усіх родів
Від вік до віка.','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_4195134'), datetime('now')),datetime('now'));
